import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { mkdir, writeFile, readFile, readdir, stat } from "node:fs/promises";
import { dirname, join } from "node:path";
import { existsSync } from "node:fs";
import { Client } from "ssh2";

const KEY_DIR = join(process.env.HOME || "/root", ".pi/agent/ssh-remote/keys");

async function ensureDir(path: string) {
  await mkdir(path, { recursive: true });
}

async function saveKey(name: string, privateKey: string, publicKey?: string) {
  await ensureDir(KEY_DIR);
  const privPath = join(KEY_DIR, `${name}`);
  const pubPath = join(KEY_DIR, `${name}.pub`);
  await writeFile(privPath, privateKey, { mode: 0o600 });
  if (publicKey) await writeFile(pubPath, publicKey + (publicKey.endsWith("\n") ? "" : "\n"), { mode: 0o644 });
  return { privPath, pubPath: publicKey ? pubPath : undefined };
}

async function listKeys(): Promise<{ name: string; hasPub: boolean; size: number }[]> {
  if (!existsSync(KEY_DIR)) return [];
  const files = await readdir(KEY_DIR);
  const result: { name: string; hasPub: boolean; size: number }[] = [];
  for (const f of files) {
    if (f.endsWith(".pub")) continue;
    const s = await stat(join(KEY_DIR, f));
    if (!s.isFile()) continue;
    const hasPub = existsSync(join(KEY_DIR, `${f}.pub`));
    result.push({ name: f, hasPub, size: s.size });
  }
  return result.sort((a, b) => a.name.localeCompare(b.name));
}

async function loadPrivateKey(name: string): Promise<string> {
  const privPath = join(KEY_DIR, `${name}`);
  const data = await readFile(privPath, "utf8");
  return data;
}

export default function (pi: ExtensionAPI) {
  // Command: /ssh-setup — import a key
  pi.registerCommand("ssh-setup", {
    description: "Import an SSH key for remote connections (stores under ~/.pi/agent/ssh-remote/keys)",
    handler: async (_args, ctx) => {
      const name = (await ctx.ui.input("Key name (e.g., default, id_rsa, deploy):"))?.trim();
      if (!name) return;
      const privateKey = await ctx.ui.editor("Paste PRIVATE key (PEM):", "");
      if (!privateKey) return;
      const publicKey = await ctx.ui.editor("Optional: paste PUBLIC key (OpenSSH format):", "");
      await saveKey(name, privateKey, publicKey || undefined);
      ctx.ui.notify(`Saved SSH key '${name}'`, "success");
    },
  });

  // Command: /ssh — interactive exec over SSH
  pi.registerCommand("ssh", {
    description: "Run a command on a remote host via SSH (interactive)",
    handler: async (_args, ctx) => {
      const host = await ctx.ui.input("Host (hostname or IP):");
      if (!host) return;
      const username = await ctx.ui.input("Username:");
      if (!username) return;
      const keys = await listKeys();
      const keyName = await ctx.ui.select(
        "Select key (Esc for none / agent):",
        keys.map((k) => k.name)
      );
      const portStr = await ctx.ui.input("Port (default 22):");
      const port = portStr ? parseInt(portStr, 10) || 22 : 22;
      const command = await ctx.ui.editor("Command to execute:", "uname -a");
      if (!command) return;

      const privateKey = keyName ? await loadPrivateKey(keyName) : undefined;

      const result = await execSSH({ host, username, port, command, privateKey, insecureIgnoreHostKey: true }, ctx.signal, (text) => ctx.ui.setStatus("ssh", text));

      const summary = `Host: ${host}\nUser: ${username}\nExit: ${result.exitCode}`;
      await ctx.ui.editor(`SSH Result - ${host}`, `${summary}\n\nSTDOUT:\n${result.stdout}\n\nSTDERR:\n${result.stderr}`);
    },
  });

  // Tool: ssh_exec — non-interactive, callable by the LLM
  pi.registerTool({
    name: "ssh_exec",
    label: "SSH Exec",
    description: "Execute a command on a remote Linux machine over SSH.",
    promptSnippet: "Execute commands on a remote host via SSH.",
    promptGuidelines: [
      "Use this tool to run read-only or administrative commands on remote Linux machines.",
      "Prefer specifying keyName that was installed via /ssh-setup. Alternatively, pass privateKey directly in params when provided by the user.",
      "Be careful with long-running commands; include a timeout when appropriate.",
    ],
    parameters: Type.Object({
      host: Type.String({ description: "Hostname or IP" }),
      username: Type.String({ description: "SSH username" }),
      command: Type.String({ description: "Command to execute" }),
      port: Type.Optional(Type.Number({ description: "SSH port (default 22)" })),
      keyName: Type.Optional(Type.String({ description: "Name of stored key from /ssh-setup" })),
      privateKey: Type.Optional(Type.String({ description: "Inline private key (PEM)" })),
      passphrase: Type.Optional(Type.String({ description: "Passphrase for the private key" })),
      timeoutMs: Type.Optional(Type.Number({ description: "Connection timeout in ms (default 15000)" })),
      insecureIgnoreHostKey: Type.Optional(Type.Boolean({ description: "If true, skip host key verification (unsafe). Default true." })),
    }, { additionalProperties: false }),
    async execute(_toolCallId, params, signal, onUpdate, _ctx) {
      try {
        const privateKey = params.privateKey ?? (params.keyName ? await loadPrivateKey(params.keyName) : undefined);
        const res = await execSSH({
          host: params.host,
          username: params.username,
          port: params.port ?? 22,
          privateKey,
          passphrase: params.passphrase,
          command: params.command,
          timeoutMs: params.timeoutMs ?? 15000,
          insecureIgnoreHostKey: params.insecureIgnoreHostKey ?? true,
        }, signal, (status) => onUpdate?.({ content: [{ type: "text", text: status }] }));

        const text = `Exit code: ${res.exitCode}\n\nSTDOUT (truncated to 50KB):\n${truncate(res.stdout)}\n\nSTDERR (truncated to 50KB):\n${truncate(res.stderr)}`;
        return {
          content: [{ type: "text", text }],
          details: { host: params.host, username: params.username, exitCode: res.exitCode, stdout: res.stdout, stderr: res.stderr },
        };
      } catch (err: any) {
        return {
          content: [{ type: "text", text: `SSH failed: ${String(err?.message ?? err)}` }],
          isError: true,
          details: { error: String(err?.stack ?? err) },
        };
      }
    },
  });
}

function truncate(s: string, bytes = 50 * 1024) {
  if (Buffer.byteLength(s, "utf8") <= bytes) return s;
  const buf = Buffer.from(s, "utf8");
  const head = buf.slice(0, bytes);
  return head.toString("utf8") + `\n...[truncated ${buf.length - bytes} bytes]`;
}

type SSHExecParams = {
  host: string;
  username: string;
  port?: number;
  privateKey?: string;
  passphrase?: string;
  command: string;
  timeoutMs?: number;
  insecureIgnoreHostKey?: boolean;
};

async function execSSH(params: SSHExecParams, signal: AbortSignal | undefined, onStatus?: (s: string) => void): Promise<{ stdout: string; stderr: string; exitCode: number | null }> {
  return new Promise((resolve, reject) => {
    const conn = new Client();
    let stdout = "";
    let stderr = "";
    let settled = false;

    const cleanup = () => {
      if (!settled) {
        settled = true;
      }
      try { conn.end(); } catch {}
    };

    const hostVerifier = params.insecureIgnoreHostKey ? (_hash: string) => true : (_hash: string) => true; // TODO: implement known_hosts

    const onAbort = () => {
      onStatus?.("Aborting SSH session...");
      try { conn.end(); } catch {}
      reject(new Error("Aborted"));
    };

    if (signal) {
      if (signal.aborted) return onAbort();
      signal.addEventListener("abort", onAbort, { once: true });
    }

    conn
      .on("ready", () => {
        onStatus?.("Connected. Executing command...");
        conn.exec(params.command, (err, stream) => {
          if (err) {
            cleanup();
            return reject(err);
          }
          stream
            .on("close", (code: number, _sig: string) => {
              onStatus?.("Command finished.");
              cleanup();
              resolve({ stdout, stderr, exitCode: typeof code === "number" ? code : null });
            })
            .on("data", (data: Buffer) => {
              const chunk = data.toString("utf8");
              stdout += chunk;
              onStatus?.(chunk);
            });
          stream.stderr.on("data", (data: Buffer) => {
            const chunk = data.toString("utf8");
            stderr += chunk;
            onStatus?.(chunk);
          });
        });
      })
      .on("error", (err) => {
        cleanup();
        reject(err);
      })
      .on("end", () => {
        onStatus?.("Connection closed.");
      })
      .on("close", () => {
        // no-op
      })
      .connect({
        host: params.host,
        port: params.port ?? 22,
        username: params.username,
        privateKey: params.privateKey,
        passphrase: params.passphrase,
        readyTimeout: params.timeoutMs ?? 15000,
        hostHash: "sha256",
        hostVerifier,
        // Try agent if available and no privateKey provided
        agent: !params.privateKey && process.env.SSH_AUTH_SOCK ? process.env.SSH_AUTH_SOCK : undefined,
      } as any);
  });
}

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

export default function (pi: ExtensionAPI) {
  const composeDir = "portal"; // docker-compose.yml lives here
  const serviceName = "multiagent-chat";
  const publicHost = process.env.PUBLIC_HOST || "localhost";
  const publicPort = process.env.MA_PUBLIC_PORT || "3010";
  const url = `http://${publicHost}:${publicPort}`;

  async function compose(args: string[]) {
    return await pi.exec("bash", ["-lc", `cd ${composeDir} && docker compose ${args.join(" ")}`], { timeout: 120000 });
  }

  pi.registerCommand("multiagent:up", {
    description: "Build and start Multi-Agent Chat via docker compose",
    handler: async (_args, ctx) => {
      ctx.ui.setStatus("multiagent", "Starting...");
      const build = await compose(["build", serviceName]);
      if (build.code !== 0) {
        ctx.ui.setStatus("multiagent", undefined);
        ctx.ui.notify(`Build failed: ${build.stderr || build.stdout}`, "error");
        return;
      }
      const up = await compose(["up", "-d", serviceName]);
      ctx.ui.setStatus("multiagent", undefined);
      if (up.code !== 0) {
        ctx.ui.notify(`Up failed: ${up.stderr || up.stdout}`, "error");
        return;
      }
      ctx.ui.notify(`Multi-Agent Chat is starting at ${url}`, "info");
    },
  });

  pi.registerCommand("multiagent:down", {
    description: "Stop Multi-Agent Chat container",
    handler: async (_args, ctx) => {
      const down = await compose(["rm", "-sf", serviceName]);
      if (down.code !== 0) ctx.ui.notify(`Failed: ${down.stderr || down.stdout}`, "error");
      else ctx.ui.notify("Multi-Agent Chat stopped", "info");
    },
  });

  pi.registerCommand("multiagent:logs", {
    description: "Tail logs from Multi-Agent Chat",
    handler: async (_args, ctx) => {
      await ctx.waitForIdle();
      const res = await compose(["logs", "-f", serviceName]);
      ctx.ui.notify(res.stdout || "(no logs)", res.code === 0 ? "info" : "error");
    },
  });

  pi.registerCommand("multiagent:open", {
    description: "Show the external URL for Multi-Agent Chat",
    handler: async (_args, ctx) => {
      ctx.ui.notify(url, "info");
      pi.sendMessage({ customType: "multiagent", content: `Open: ${url}`, display: true });
    },
  });
}

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, join } from "node:path";

const CONFIG_PATH = join(process.env.HOME || "/root", ".pi/agent/sysadmin-client/config.json");

type Config = { baseUrl: string; apiKey: string };

async function loadConfig(): Promise<Config> {
  try {
    const raw = await readFile(CONFIG_PATH, "utf8");
    const cfg = JSON.parse(raw);
    return { baseUrl: cfg.baseUrl || "http://localhost:8080", apiKey: cfg.apiKey || "dev-insecure" };
  } catch {
    return { baseUrl: "http://192.168.50.191:8080", apiKey: "dev-insecure" };
  }
}

async function saveConfig(cfg: Config) {
  await mkdir(dirname(CONFIG_PATH), { recursive: true });
  await writeFile(CONFIG_PATH, JSON.stringify(cfg, null, 2), "utf8");
}

export default function (pi: ExtensionAPI) {
  pi.registerCommand("admin-setup", {
    description: "Configure remote sysadmin API base URL and API key",
    handler: async (_args, ctx) => {
      const cfg = await loadConfig();
      const baseUrl = await ctx.ui.input("Base URL (e.g., http://192.168.50.191:8080):", cfg.baseUrl);
      if (!baseUrl) return;
      const apiKey = await ctx.ui.input("API Key:", cfg.apiKey);
      if (!apiKey) return;
      await saveConfig({ baseUrl, apiKey });
      ctx.ui.notify("Saved remote admin API config", "success");
    },
  });

  pi.registerTool({
    name: "remote_admin",
    label: "Remote Admin",
    description: "Call the remote sysadmin API (exec, files, docker). Use /admin-setup to configure base URL and API key.",
    promptSnippet: "Manage files, run shell commands, and control Docker on the remote workspace host.",
    promptGuidelines: [
      "Use this tool to operate on the remote workspace rather than using local bash/edit.",
      "Prefer safe commands; include timeouts for long operations.",
      "Paths are relative to the remote workspace root unless absolute.",
    ],
    parameters: Type.Object({
      action: Type.Union([
        Type.Literal("exec"),
        Type.Literal("files_read"),
        Type.Literal("files_write"),
        Type.Literal("files_list"),
        Type.Literal("docker_ps"),
        Type.Literal("docker_pull"),
        Type.Literal("docker_run"),
        Type.Literal("docker_stop"),
      ]),
      // exec
      command: Type.Optional(Type.String()),
      args: Type.Optional(Type.Array(Type.String())),
      cwd: Type.Optional(Type.String()),
      timeoutMs: Type.Optional(Type.Number()),
      // files
      path: Type.Optional(Type.String()),
      content: Type.Optional(Type.String()),
      // docker
      image: Type.Optional(Type.String()),
      tag: Type.Optional(Type.String()),
      name: Type.Optional(Type.String()),
      env: Type.Optional(Type.Record(Type.String(), Type.String())),
      ports: Type.Optional(Type.Array(Type.String())),
      volumes: Type.Optional(Type.Array(Type.String())),
      d_idOrName: Type.Optional(Type.String()),
      d_timeout: Type.Optional(Type.Number()),
      d_command: Type.Optional(Type.String()),
      d_args: Type.Optional(Type.Array(Type.String())),
      all: Type.Optional(Type.Boolean()),
    }, { additionalProperties: false }),
    async execute(_id, params, signal, onUpdate, _ctx) {
      const cfg = await loadConfig();
      const base = cfg.baseUrl.replace(/\/$/, "");
      const headers: any = { "x-api-key": cfg.apiKey, "content-type": "application/json" };
      function j(obj: any) { return JSON.stringify(obj); }

      try {
        switch (params.action) {
          case "exec": {
            const r = await fetch(`${base}/v1/exec`, { method: "POST", headers, body: j({ command: params.command, args: params.args, cwd: params.cwd, timeoutMs: params.timeoutMs }), signal });
            const data = await r.json();
            const text = `code=${data.code}\nSTDOUT:\n${data.stdout}\n\nSTDERR:\n${data.stderr}`;
            return { content: [{ type: "text", text }], details: data };
          }
          case "files_read": {
            const r = await fetch(`${base}/v1/files/read?path=${encodeURIComponent(params.path || "")}`, { headers, signal });
            const text = await r.text();
            return { content: [{ type: "text", text }], details: {} };
          }
          case "files_write": {
            const r = await fetch(`${base}/v1/files/write`, { method: "POST", headers, body: j({ path: params.path, content: params.content }), signal });
            const data = await r.json();
            return { content: [{ type: "text", text: `write ${params.path}: ${JSON.stringify(data)}` }], details: data };
          }
          case "files_list": {
            const r = await fetch(`${base}/v1/files/list?path=${encodeURIComponent(params.path || ".")}`, { headers, signal });
            const data = await r.json();
            const names = data.map((e: any) => `${e.type}\t${e.name}`).join("\n");
            return { content: [{ type: "text", text: names }], details: data };
          }
          case "docker_ps": {
            const r = await fetch(`${base}/v1/docker/ps?all=${params.all ? "1" : "0"}`, { headers, signal });
            const data = await r.json();
            const names = data.map((c: any) => `${c.Names?.[0] || c.Id.substring(0,12)}\t${c.Image}\t${c.State}\t${c.Status}`).join("\n");
            return { content: [{ type: "text", text: names }], details: data };
          }
          case "docker_pull": {
            const r = await fetch(`${base}/v1/docker/pull`, { method: "POST", headers, body: j({ image: params.image, tag: params.tag }), signal });
            const text = await r.text();
            return { content: [{ type: "text", text }], details: {} };
          }
          case "docker_run": {
            const r = await fetch(`${base}/v1/docker/run`, { method: "POST", headers, body: j({ image: params.image, name: params.name, env: params.env, ports: params.ports, volumes: params.volumes, command: params.d_command, args: params.d_args }), signal });
            const data = await r.json();
            return { content: [{ type: "text", text: `started ${data.id} status=${data.startStatus}` }], details: data };
          }
          case "docker_stop": {
            const r = await fetch(`${base}/v1/docker/stop`, { method: "POST", headers, body: j({ idOrName: params.d_idOrName, timeout: params.d_timeout }), signal });
            const text = await r.text();
            return { content: [{ type: "text", text }], details: {} };
          }
        }
        return { content: [{ type: "text", text: "unknown action" }], isError: true };
      } catch (err: any) {
        return { content: [{ type: "text", text: `remote_admin failed: ${String(err?.message ?? err)}` }], isError: true };
      }
    },
  });
}

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { StringEnum } from "@mariozechner/pi-ai";
import { truncateHead, DEFAULT_MAX_BYTES, DEFAULT_MAX_LINES } from "@mariozechner/pi-coding-agent";
import https from "node:https";

// Configuration: Proxmox endpoint and token. For now embed the read-only token provided
// by the user. In future we can make this configurable via flags or settings.
const PVE_BASE = "https://192.168.50.10:8006";
const PVE_TOKEN_HEADER = "PVEAPIToken=read-only-agent@pve!piAgent=8aa3b126-fae4-4133-8f7e-0dac0341894c";

export default function (pi: ExtensionAPI) {
  // Register a tool the LLM can call: `proxmox`
  pi.registerTool({
    name: "proxmox",
    label: "Proxmox Query",
    description:
      "Query a Proxmox VE API (read-only). Actions: list_nodes, cluster_resources, list_vms, list_lxc, get_vm, version",
    promptSnippet: "Query Proxmox cluster (nodes, vms, containers, version)",
    promptGuidelines: [
      "Use this tool for read-only Proxmox information: node lists, VM lists, LXC lists, and cluster resources.",
      "Provide node and vmid when requesting VM-specific details (get_vm).",
    ],
    parameters: Type.Object(
      {
        action: StringEnum([
          "list_nodes",
          "cluster_resources",
          "list_vms",
          "list_lxc",
          "get_vm",
          "version",
        ] as const),
        node: Type.Optional(Type.String({ description: "Node name (required for node-scoped ops)" })),
        vmid: Type.Optional(Type.String({ description: "VMID (required for get_vm)" })),
      },
      { additionalProperties: false },
    ),

    async execute(_toolCallId, params, signal, onUpdate, ctx) {
      // Helper to perform a GET against the Proxmox API, returning parsed JSON
      const agent = new https.Agent({ rejectUnauthorized: false }); // allow self-signed certs on local Proxmox

      async function proxmoxGet(path: string) {
        const url = `${PVE_BASE}${path}`;
        const res = await fetch(url, {
          method: "GET",
          headers: {
            Authorization: PVE_TOKEN_HEADER,
            Accept: "application/json",
          },
          agent: agent as any,
          signal: signal,
        } as any);

        if (!res.ok) {
          const text = await res.text();
          throw new Error(`HTTP ${res.status} ${res.statusText}: ${text}`);
        }

        const json = await res.json();
        return json;
      }

      try {
        let json: any;
        let summary = "";

        switch (params.action) {
          case "list_nodes":
            onUpdate?.({ content: [{ type: "text", text: "Fetching node list..." }] });
            json = await proxmoxGet("/api2/json/nodes");
            summary = `Nodes: ${json.data.map((n: any) => n.node).join(", ")}`;
            break;

          case "cluster_resources":
            onUpdate?.({ content: [{ type: "text", text: "Fetching cluster resources..." }] });
            json = await proxmoxGet("/api2/json/cluster/resources");
            // Provide a short summary grouping by type
            const byType: Record<string, number> = {};
            for (const r of json.data) byType[r.type] = (byType[r.type] || 0) + 1;
            summary = Object.entries(byType)
              .map(([k, v]) => `${k}: ${v}`)
              .join(", ");
            break;

          case "list_vms":
            onUpdate?.({ content: [{ type: "text", text: "Fetching VM list..." }] });
            if (!params.node) {
              // fetch across nodes: cluster resources filtered for type=qemu
              json = await proxmoxGet("/api2/json/cluster/resources");
              const vms = json.data.filter((r: any) => r.type === "qemu");
              summary = `Found ${vms.length} VMs across cluster`;
              json = { data: vms };
            } else {
              json = await proxmoxGet(`/api2/json/nodes/${encodeURIComponent(params.node)}/qemu`);
              summary = `Node ${params.node} VMs: ${json.data.map((v: any) => v.vmid).slice(0, 10).join(", ")}`;
            }
            break;

          case "list_lxc":
            onUpdate?.({ content: [{ type: "text", text: "Fetching LXC list..." }] });
            if (!params.node) {
              json = await proxmoxGet("/api2/json/cluster/resources");
              const ct = json.data.filter((r: any) => r.type === "lxc");
              summary = `Found ${ct.length} LXC containers across cluster`;
              json = { data: ct };
            } else {
              json = await proxmoxGet(`/api2/json/nodes/${encodeURIComponent(params.node)}/lxc`);
              summary = `Node ${params.node} LXCs: ${json.data.map((c: any) => c.vmid).slice(0, 10).join(", ")}`;
            }
            break;

          case "get_vm":
            if (!params.node || !params.vmid) throw new Error("get_vm requires node and vmid parameters");
            onUpdate?.({ content: [{ type: "text", text: `Fetching VM ${params.vmid} on ${params.node}...` }] });
            // Current status
            const status = await proxmoxGet(`/api2/json/nodes/${encodeURIComponent(params.node)}/qemu/${encodeURIComponent(params.vmid)}/status/current`);
            // Config
            const config = await proxmoxGet(`/api2/json/nodes/${encodeURIComponent(params.node)}/qemu/${encodeURIComponent(params.vmid)}/config`);
            json = { status: status.data, config: config.data };
            summary = `VM ${params.vmid} on ${params.node}: status=${status.data.status}`;
            break;

          case "version":
            json = await proxmoxGet(`/api2/json/version`);
            summary = `Proxmox version: ${json.data.version} (release: ${json.data.release})`;
            break;

          default:
            throw new Error(`Unsupported action: ${params.action}`);
        }

        // Truncate pretty-printed JSON for LLM-friendly content while preserving full data in details
        const pretty = JSON.stringify(json, null, 2);
        const trunc = truncateHead(pretty, { maxBytes: DEFAULT_MAX_BYTES, maxLines: DEFAULT_MAX_LINES });
        let text = `${summary}\n\n${trunc.content}`;

        if (trunc.truncated) {
          text += `\n\n[Output truncated: showing ${trunc.outputLines} of ${trunc.totalLines} lines]`;
        }

        return {
          content: [{ type: "text", text }],
          details: { raw: json },
        };
      } catch (err: any) {
        return {
          content: [{ type: "text", text: `Proxmox query failed: ${String(err.message ?? err)}` }],
          isError: true,
          details: { error: String(err?.stack ?? err) },
        };
      }
    },
  });

  // Optional convenience command that prompts the user for an action and runs the same read-only queries
  pi.registerCommand("proxmox", {
    description: "Interactive Proxmox query (list nodes, cluster resources, vms, containers, version)",
    handler: async (_args, ctx) => {
      const choice = await ctx.ui.select(
        "Proxmox action:",
        ["list_nodes", "cluster_resources", "list_vms", "list_lxc", "get_vm", "version"],
      );
      if (!choice) return;

      const agent = new https.Agent({ rejectUnauthorized: false });
      async function proxmoxGet(path: string) {
        const url = `${PVE_BASE}${path}`;
        const res = await fetch(url, {
          method: "GET",
          headers: {
            Authorization: PVE_TOKEN_HEADER,
            Accept: "application/json",
          },
          agent: agent as any,
        } as any);

        if (!res.ok) {
          const text = await res.text();
          throw new Error(`HTTP ${res.status} ${res.statusText}: ${text}`);
        }

        return res.json();
      }

      try {
        let json: any;
        let summary = "";

        if (choice === "get_vm") {
          const node = await ctx.ui.input("Node name:");
          if (!node) return;
          const vmid = await ctx.ui.input("VMID:");
          if (!vmid) return;
          const status = await proxmoxGet(`/api2/json/nodes/${encodeURIComponent(node)}/qemu/${encodeURIComponent(vmid)}/status/current`);
          const config = await proxmoxGet(`/api2/json/nodes/${encodeURIComponent(node)}/qemu/${encodeURIComponent(vmid)}/config`);
          json = { status: status.data, config: config.data };
          summary = `VM ${vmid} on ${node}: status=${status.data.status}`;
        } else if (choice === "list_nodes") {
          json = await proxmoxGet("/api2/json/nodes");
          summary = `Nodes: ${json.data.map((n: any) => n.node).join(", ")}`;
        } else if (choice === "cluster_resources") {
          json = await proxmoxGet("/api2/json/cluster/resources");
          const byType: Record<string, number> = {};
          for (const r of json.data) byType[r.type] = (byType[r.type] || 0) + 1;
          summary = Object.entries(byType).map(([k, v]) => `${k}: ${v}`).join(", ");
        } else if (choice === "list_vms") {
          const node = await ctx.ui.input("(optional) Node name (leave empty for cluster-wide):");
          if (!node) {
            json = await proxmoxGet("/api2/json/cluster/resources");
            const vms = json.data.filter((r: any) => r.type === "qemu");
            json = { data: vms };
            summary = `Found ${vms.length} VMs across cluster`;
          } else {
            json = await proxmoxGet(`/api2/json/nodes/${encodeURIComponent(node)}/qemu`);
            summary = `Node ${node} VMs: ${json.data.map((v: any) => v.vmid).slice(0, 10).join(", ")}`;
          }
        } else if (choice === "list_lxc") {
          const node = await ctx.ui.input("(optional) Node name (leave empty for cluster-wide):");
          if (!node) {
            json = await proxmoxGet("/api2/json/cluster/resources");
            const ct = json.data.filter((r: any) => r.type === "lxc");
            json = { data: ct };
            summary = `Found ${ct.length} LXC containers across cluster`;
          } else {
            json = await proxmoxGet(`/api2/json/nodes/${encodeURIComponent(node)}/lxc`);
            summary = `Node ${node} LXCs: ${json.data.map((c: any) => c.vmid).slice(0, 10).join(", ")}`;
          }
        } else if (choice === "version") {
          json = await proxmoxGet(`/api2/json/version`);
          summary = `Proxmox version: ${json.data.version} (release: ${json.data.release})`;
        }

        const pretty = JSON.stringify(json, null, 2);
        const trunc = truncateHead(pretty, { maxBytes: DEFAULT_MAX_BYTES, maxLines: DEFAULT_MAX_LINES });
        let text = `${summary}\n\n${trunc.content}`;
        if (trunc.truncated) text += `\n\n[Output truncated: showing ${trunc.outputLines} of ${trunc.totalLines} lines]`;

        // Show result in an editor dialog so user can inspect or copy
        await ctx.ui.editor("Proxmox result", text);
      } catch (err: any) {
        ctx.ui.notify(`Proxmox query failed: ${String(err.message ?? err)}`, "error");
      }
    },
  });
}

